import{_ as a,o as t,c as s,a3 as o}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"69G. Hazardous Weather Conditions","description":"","frontmatter":{"title":"69G. Hazardous Weather Conditions","eba":"Mental Health Services 2024-2028","topics":["leave","ohs"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/ohs/69G-hazardous-weather-conditions.md","filePath":"ebas/mental-health/common-terms/ohs/69G-hazardous-weather-conditions.md"}'),r={name:"ebas/mental-health/common-terms/ohs/69G-hazardous-weather-conditions.md"};function n(i,e,h,d,l,c){return t(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="_69g-hazardous-weather-conditions" tabindex="-1">69G. Hazardous Weather Conditions <a class="header-anchor" href="#_69g-hazardous-weather-conditions" aria-label="Permalink to &quot;69G. Hazardous Weather Conditions&quot;">​</a></h1><p><strong>(a)</strong> Employers recognise weather may create an occupational health and safety hazard.</p><p><strong>(b)</strong> Hazardous weather conditions may include but are not necessarily limited to storms, heavy rain, hail, high wind, lightning, natural disasters such as floods and bush fires, extreme temperatures, fog, severe dust storms, and where the epidemic thunderstorm asthma risk forecast is high. Further provisions in relation to disasters such as floods and bush fires can be found in <a href="/eba/ebas/mental-health/common-terms/leave/41-special-disaster-leave.html">clause 41</a> (Special Disaster Leave).</p><p><strong>(c)</strong> Where weather conditions create a potential risk to an individual’s health and safety, this will be reported and actions will be taken to assess the risk and implement the hierarchy of controls to reduce the risk as far as reasonably practicable. This may include an adjustment to work location (including working from home), or utilising an alternative mode of engagement (such as telehealth).</p><p><strong>(d)</strong> Where an Employee makes such a report the Employer must provide a response to the Employee(s) in a timely manner.</p>',5)])])}const p=a(r,[["render",n]]);export{u as __pageData,p as default};
